+export function applyWithScopedRuleIgnores(text: string, ruleAlias: string | undefined, knownRuleAliases: string[], apply: (text: string) => string): string {
+  const knownAliases = new Set(knownRuleAliases.map((alias) => alias.toLowerCase()));
