+  let cursor = 0;
+  ignoredRanges.forEach(([start, end], index) => {
+    replacements.push(text.substring(start, end));
+    const placeholder = `\\u0000${index}\\u0000`;
+    protectedText += text.substring(cursor, start) + placeholder;
+    cursor = end;
+  });
+  protectedText += text.substring(cursor);
+
+  let result = apply(protectedText);
+  replacements.forEach((replacement, index) => {
+    result = result.replace(`\\u0000${index}\\u0000`, replacement);
+  });
+  return result;
+}
+
+function getIgnoredLineRanges(text: string, ruleAlias: string | undefined, knownAliases: Set<string>): [number, number][] {
+  const lines = getLines(text);
+  const ignoredLineNumbers = new Set<number>();
+  const ignoredMarkerLines = getIgnoredMarkerLines(text, lines);
+  const scopes: RuleScope[] = [];
+
+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    const line = lines[lineIndex];
+    if (ignoredMarkerLines.has(lineIndex)) {
+      continue;
+    }
