+    // A marker is always protected, even when its arguments have no effect.
+    ignoredLineNumbers.add(lineIndex);
+    switch (marker.action) {
+      case 'disable':
+        if (marker.hasRuleList ? marker.rules.size > 0 : true) {
+          scopes.push({allRules: !marker.hasRuleList, rules: marker.rules, enabledRules: new Set()});
+        }
+        break;
+      case 'enable':
+        enableScopes(scopes, marker);
+        break;
+      case 'next-line':
+      case 'next-lines':
+        if ((marker.hasRuleList ? marker.rules.size > 0 : true) && marker.lineCount !== undefined) {
+          const end = Math.min(lines.length - 1, lineIndex + marker.lineCount);
