+  lines.forEach((line, lineIndex) => {
+    if (ignoredRanges.some((range) => range.start.offset <= line.start && line.start < range.end.offset)) {
+      ignoredLines.add(lineIndex);
+    }
+  });
+  return ignoredLines;
+}
+
+function parseMarker(line: string, knownAliases: Set<string>): Marker | null {
+  const match = line.match(markerLine);
+  if (match === null) {
+    return null;
+  }
+  const content = (match[1] ?? match[2]).trim();
+  const nextLines = /^linter-disable-next-n-lines:[ \	]*(\\S+)(?:[ \	]+(.*))?$/i.exec(content);
+  if (nextLines !== null) {
+    const count = /^[1-9]\\d*$/.test(nextLines[1]) ? Number(nextLines[1]) : undefined;
+    return {action: 'next-lines', hasRuleList: nextLines[2] !== undefined, rules: normalizeRules(nextLines[2] ?? '', knownAliases), lineCount: count};
+  }
+
+  const actionMatch = /^linter-(disable-next-line|disable|enable)(?:[ \	]+(.*))?$/i.exec(content);
+  if (actionMatch === null) {
+    return null;
+  }
+  const action = actionMatch[1].toLowerCase();
+  return {
+    action: action === 'disable-next-line' ? 'next-line' : action as 'disable' | 'enable',
+    hasRuleList: actionMatch[2] !== undefined,
+    rules: normalizeRules(actionMatch[2] ?? '', knownAliases),
+    lineCount: action === 'disable-next-line' ? 1 : undefined,
+  };
+}
+
+function normalizeRules(ruleList: string, knownAliases: Set<string>): Set<string> {
+  return new Set(ruleList.split(',').map((rule) => rule.trim().toLowerCase()).filter((rule) => rule !== '' && knownAliases.has(rule)));
+}
+
+function isDisabled(scopes: RuleScope[], ruleAlias: string | undefined): boolean {
+  return scopes.some((scope) => scope.allRules ? ruleAlias === undefined || !scope.enabledRules.has(ruleAlias) : ruleAlias !== undefined && scope.rules.has(ruleAlias));
+}
+
+function isMarkerDisabledForRule(marker: Marker, ruleAlias: string | undefined): boolean {
+  return !marker.hasRuleList || (ruleAlias !== undefined && marker.rules.has(ruleAlias));
+}
+
+function enableScopes(scopes: RuleScope[], marker: Marker): void {
+  if (!marker.hasRuleList) {
+    scopes.pop();
+    return;
+  }
+  marker.rules.forEach((rule) => {
+    for (let index = scopes.length - 1; index >= 0; index--) {
+      const scope = scopes[index];
+      if (scope.allRules && !scope.enabledRules.has(rule)) {
+        scope.enabledRules.add(rule);
+        break;
+      }
+      if (!scope.allRules && scope.rules.delete(rule)) {
+        if (scope.rules.size === 0) {
+          scopes.splice(index, 1);
+        }
+        break;
+      }
+    }
+  });
+}
