+    let end = lines[lineIndex].end;
+    while (lineIndex + 1 < lines.length && lineNumbers.has(lineIndex + 1)) {
+      end = lines[++lineIndex].end;
+    }
+    ranges.push([start, end]);
+  }
+  return ranges;
